// node_conv_218 — pointwise (1x1) conv2d on tiled-streaming contract.
//   IC=256, OC=128, IH=IW=OH=OW=56, stride=1, padding=0, MP=4.
//   channel_tile=32 → IN_BEATS=8, OUT_BEATS=4. K_TOTAL=256, OC_PASSES=32.
//   Latency = IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6) = 8 + 32*1030 = 32968.
module node_conv_218 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam integer IC=256, OC=128, IH=56, IW=56, OH=56, OW=56, KH=1, KW=1;
    localparam integer K_TOTAL=IC*KH*KW;
    localparam integer MP=4;
    localparam integer OC_PASSES=(OC+MP-1)/MP;
    localparam integer CHANNEL_TILE=32;
    localparam integer IN_BEATS=(IC+CHANNEL_TILE-1)/CHANNEL_TILE;
    localparam integer OUT_BEATS=(OC+CHANNEL_TILE-1)/CHANNEL_TILE;
    localparam integer TILE_BITS=CHANNEL_TILE*8;
    localparam integer SCALE_MULT=23733, SCALE_SHIFT=20;
    localparam integer PROD_W=16, ACC_W=24, BIAS_W=32, BIASED_W=33, SCALE_CONST_W=16, SCALED_W=BIASED_W+SCALE_CONST_W;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST=SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF={{(SCALED_W-1){1'b0}},1'b1}<<<(SCALE_SHIFT-1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1=SCALE_ROUND_HALF-{{(SCALED_W-1){1'b0}},1'b1};
    (* rom_style="block", ram_style="block" *) reg signed [7:0] weights[0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases[0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_218_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_218_bias.hex", biases);
    end
    reg signed [7:0] in_latch[0:IC-1];
    reg [OC*8-1:0] out_pack;
    localparam [2:0] ST_LOAD=0,ST_RUNNING=1,ST_BIAS=2,ST_SCALE=3,ST_OUTPUT=4,ST_EMIT=5;
    reg [2:0] state;
    reg [3:0] in_beat_idx, out_beat_idx;
    reg [11:0] active_emit_count;
    reg [5:0] pixel_row, pixel_col, oc_group;
    reg [1:0] lane_counter;
    reg [8:0] k_counter;
    reg mac_done_issuing;
    reg [1:0] mac_drain;
    reg signed [7:0] weight_q, act_q;
    (* use_dsp="yes" *) reg signed [PROD_W-1:0] mul_q;
    reg signed [ACC_W-1:0] acc[0:MP-1];
    reg signed [BIASED_W-1:0] biased[0:MP-1];
    reg signed [SCALED_W-1:0] scaled[0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;
    reg v_q1, v_q2;
    reg [1:0] lane_q1, lane_q2;
    integer i, lane, b, global_oc;
    always @(posedge clk) begin
        if (state==ST_LOAD && valid_in && ready_in)
            for (b=0;b<CHANNEL_TILE;b=b+1)
                in_latch[in_beat_idx*CHANNEL_TILE+b] <= $signed(data_in[b*8 +: 8]);
        if (v_q2) acc[lane_q2] <= acc[lane_q2] + mul_q;
        if ((state==ST_LOAD && valid_in && ready_in && in_beat_idx==IN_BEATS-1) || (state==ST_OUTPUT))
            for (i=0;i<MP;i=i+1) acc[i] <= {ACC_W{1'b0}};
        if (state==ST_BIAS)
            for (lane=0;lane<MP;lane=lane+1)
                biased[lane] <= acc[lane] + biases[oc_group*MP+lane];
        if (state==ST_SCALE)
            for (lane=0;lane<MP;lane=lane+1)
                scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state<=ST_LOAD; ready_in<=1'b1; valid_out<=1'b0; data_out<=256'd0;
            in_beat_idx<=0; out_beat_idx<=0; active_emit_count<=0;
            pixel_row<=0; pixel_col<=0; oc_group<=0; lane_counter<=0; k_counter<=0;
            mac_done_issuing<=0; mac_drain<=0;
            weight_q<=0; act_q<=0; mul_q<=0; v_q1<=0; v_q2<=0; lane_q1<=0; lane_q2<=0;
            v_tmp<=0; out_pack<=0;
        end else begin
            v_q1 <= 1'b0;
            v_q2 <= v_q1;
            lane_q2 <= lane_q1;
            mul_q <= $signed(weight_q) * $signed(act_q);
            case (state)
                ST_LOAD: if (valid_in && ready_in) begin
                    if (in_beat_idx==IN_BEATS-1) begin
                        in_beat_idx<=0; ready_in<=1'b0; // [INVARIANT:READY_IN_GATING]
                        oc_group<=0; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=0; mac_drain<=0; state<=ST_RUNNING;
                    end else in_beat_idx<=in_beat_idx+1;
                end
                ST_RUNNING: if (!mac_done_issuing) begin
                    weight_q <= weights[(oc_group*MP+lane_counter)*K_TOTAL+k_counter];
                    act_q    <= in_latch[k_counter];
                    v_q1<=1'b1; lane_q1<=lane_counter;
                    if (lane_counter==MP-1) begin
                        lane_counter<=0;
                        if (k_counter==K_TOTAL-1) begin mac_done_issuing<=1; mac_drain<=0; end
                        else k_counter<=k_counter+1;
                    end else lane_counter<=lane_counter+1;
                end else begin
                    if (mac_drain==2'd2) state<=ST_BIAS;
                    else mac_drain<=mac_drain+1;
                end
                ST_BIAS:  state<=ST_SCALE;
                ST_SCALE: state<=ST_OUTPUT;
                ST_OUTPUT: begin
                    for (lane=0;lane<MP;lane=lane+1) begin
                        global_oc = oc_group*MP+lane;
                        v_tmp = (scaled[lane] + (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT; // [INVARIANT:ROUNDING]
                        out_pack[global_oc*8 +: 8] <= (v_tmp>127)?8'sd127:(v_tmp<-128)?-8'sd128:v_tmp[7:0];
                    end
                    if (oc_group==OC_PASSES-1) begin
                        valid_out<=1'b1; // [INVARIANT:VALID_OUT_LATENCY]
                        data_out<=out_pack[0 +: TILE_BITS];
                        out_beat_idx<=1; state<=ST_EMIT;
                    end else begin
                        oc_group<=oc_group+1; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=0; mac_drain<=0; state<=ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    if (out_beat_idx<OUT_BEATS) begin
                        data_out<=out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                        valid_out<=1'b1; out_beat_idx<=out_beat_idx+1;
                    end else begin
                        valid_out<=1'b0; ready_in<=1'b1; // [INVARIANT:READY_IN_GATING]
                        out_beat_idx<=0; state<=ST_LOAD;
                        if (active_emit_count==OH*OW-1) begin
                            active_emit_count<=0; pixel_row<=0; pixel_col<=0;
                        end else begin
                            active_emit_count<=active_emit_count+1;
                            if (pixel_col==OW-1) begin pixel_col<=0; pixel_row<=pixel_row+1; end
                            else pixel_col<=pixel_col+1;
                        end
                    end
                end
                default: state<=ST_LOAD;
            endcase
        end
    end
endmodule
